import type { ReactNode } from 'react'
import { useDroppable } from '@dnd-kit/core'
import styles from './DroppableCanvas.module.less'
import { useTypedSelector } from '@/store'

interface IProps {
  id: string
  children: ReactNode
}

const DroppableCanvas = (props: IProps) => {
  const { id, children } = props
  const { setNodeRef } = useDroppable({ id })
  const { viewportWidth, viewportHeight } = useTypedSelector(
    (state) => state.paletteSlice
  )

  return (
    <div
      ref={setNodeRef}
      className={styles.viewport}
      style={{
        width: viewportWidth,
        height: viewportHeight,
      }}
    >
      {children}
    </div>
  )
}

export default DroppableCanvas
