import styles from './BlockManagement.module.less'
import BlockSetting from './BlockSetting.tsx'
import BlockList from './BlockList.tsx'
import { useTypedSelector } from '@/store'

const BlockManagement = () => {
  const { currentPageData, currentBlock } = useTypedSelector(
    (state) => state.paletteSlice
  )

  if (!currentPageData.id) return null
  return (
    <div className={styles.componentWrapper}>
      {currentBlock.id ? <BlockSetting /> : <BlockList />}
    </div>
  )
}

export default BlockManagement
