import { useState } from 'react'
import register from '@/utils/blockRegister.ts'
import type { allBlockTypes, BlockType } from '@/types/block'
import { useTranslation } from 'react-i18next'
import styles from './BlockList.module.less'
import DraggableBlockItem from './DraggableBlockItem.tsx'
import { Tabs, TabsProps } from 'antd'

const BlockList = () => {
  const { t } = useTranslation()
  const [tabActiveKey, setTabActiveKey] = useState('page')

  const items: TabsProps['items'] = [
    {
      key: 'page',
      label: t('blocks.page_type'),
    },
    {
      key: 'global',
      label: t('blocks.global_type'),
    },
  ]

  const onChange = (key: string) => {
    setTabActiveKey(key)
  }

  return (
    <div className={styles.blockList}>
      <div className={styles.title}>{t('blocks.available_block')}</div>
      <Tabs activeKey={tabActiveKey} items={items} onChange={onChange} />
      <div id="block_list" className={styles.blockItems}>
        {[...(register.getAllBlocks()?.entries() || [])]
          .filter(([, block]) => {
            if (block.isHideInList) return false
            if (tabActiveKey === 'page') return !block.isGlobalBlock
            return block.isGlobalBlock
          })
          ?.map(([key, blockProps]) => {
            return (
              <DraggableBlockItem
                key={key}
                block={blockProps as BlockType<allBlockTypes>}
              />
            )
          })}
      </div>
    </div>
  )
}

export default BlockList
