import { useTranslation } from 'react-i18next'
import styles from './ComponentProperty.module.less'
import { useTypedSelector } from '@/store'
import { BlockPropertiesMap } from '@/constants/BlockProperties'
import register from '@/utils/blockRegister.ts'
import { Space } from 'antd'
import { useMemo } from 'react'
import { ISpecialProperty, TopLevelKey } from '@/types/block'

const ComponentProperty = () => {
  const { t } = useTranslation()
  const { currentBlock } = useTypedSelector((state) => state.paletteSlice)

  const blockOriginInfo = useMemo(() => {
    return register.getBlock(currentBlock.component)
  }, [currentBlock])

  return (
    <div className={styles.ComponentPropertyWrapper}>
      <div className={styles.title}>
        <span>{t(blockOriginInfo.label)}</span>
        <span>{t('blocks.component_property')}</span>
      </div>
      <Space direction="vertical" size={8}>
        {blockOriginInfo?.properties?.map((originProperty) => {
          const property = originProperty
          if (typeof property === 'string') {
            const Node = BlockPropertiesMap[property as TopLevelKey]
            return <Node key={property} />
          } else if ('style' in property) {
            const styleNodeKey = Object.keys(property.style)
            return styleNodeKey.map((key) => {
              if (key in BlockPropertiesMap.style) {
                const Node =
                  BlockPropertiesMap.style[
                    key as keyof (typeof BlockPropertiesMap)['style']
                  ]
                return (
                  <Node
                    key={key}
                    {...(currentBlock.props?.overWriteStyleProps?.[key] ||
                      property.style[key])}
                  />
                )
              }
            })
          } else {
            const property = originProperty as ISpecialProperty
            const key = Object.keys(property)[0] as TopLevelKey
            const props = property[key].props
            const Node = BlockPropertiesMap[key as TopLevelKey]
            return <Node key={key} {...props} />
          }
        })}
      </Space>
    </div>
  )
}

export default ComponentProperty
