import { IContainer } from '@/types/template'
import classNames from 'classnames'
import styles from './CategoryPages.module.less'
import Image from '@/components/Image'
import { useAppDispatch, useTypedSelector } from '@/store'
import { actions, effects } from '@/store/slices/palette.slice.ts'
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  type DndContextProps,
} from '@dnd-kit/core'
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
} from '@dnd-kit/sortable'
import { useSortable } from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import { EyeOutlined, EyeInvisibleOutlined } from '@ant-design/icons'
import { useMemo, type MouseEvent } from 'react'

interface IPageListProps {
  groupId: string
  categoryId: string
  categoryAllPage: IContainer[]
}

interface IPageItemProps {
  data: IContainer
  url: string | undefined
  switchPage: (id: string) => void
}

const SortableItem = (props: IPageItemProps) => {
  const { data, url, switchPage } = props
  const { attributes, listeners, setNodeRef, transform, transition } =
    useSortable({ id: data.id })
  const { currentPageData } = useTypedSelector((state) => state.paletteSlice)
  const dispatch = useAppDispatch()

  const isHide = useMemo(() => {
    return currentPageData?.props?.visible?.value === false
  }, [currentPageData])

  const handleChangePageVisible = (
    e: MouseEvent<HTMLSpanElement>,
    visible: boolean
  ) => {
    e.stopPropagation()
    const newCurrentPage = {
      ...currentPageData,
      props: {
        ...(currentPageData.props || {}),
        visible: {
          value: visible,
        },
      },
    }
    dispatch(actions.setCurrentPageData(newCurrentPage))
    dispatch(actions.syncPageDataToGroup())
  }

  return (
    <div
      ref={setNodeRef}
      style={{
        transform: CSS.Transform.toString(transform),
        transition,
      }}
      {...attributes}
      {...listeners}
      className={classNames(
        styles.page,
        currentPageData.id === data.id && styles.selected
      )}
      onClick={() => switchPage(data.id)}
    >
      <>
        {url ? (
          <Image className={styles.pageBgImg} src={url} alt="thumbnail" />
        ) : null}
        {isHide ? (
          <EyeInvisibleOutlined
            onClick={(e) => handleChangePageVisible(e, true)}
            className={classNames(
              styles.icon,
              currentPageData.id === data.id && styles.selectedIcon
            )}
          />
        ) : (
          <EyeOutlined
            onClick={(e) => handleChangePageVisible(e, false)}
            className={classNames(
              styles.icon,
              currentPageData.id === data.id && styles.selectedIcon
            )}
          />
        )}
      </>
    </div>
  )
}

const CategoryPages = (props: IPageListProps) => {
  const { groupId, categoryId, categoryAllPage } = props
  const { globalData } = useTypedSelector((state) => state.paletteSlice)
  const dispatch = useAppDispatch()
  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 10,
      },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  )

  const switchPage = (pageId: string) => {
    const selectedPageData = globalData
      .find((g) => g.groupId === groupId)
      ?.children.find((c) => c.categoryId === categoryId)
      ?.pageData.find((p) => p.id === pageId)
    if (selectedPageData) {
      dispatch(actions.setCurrentPageData(selectedPageData))
      // 切页后保存数据
      dispatch(effects.saveEMenuProConfig())
    }
  }

  const handleSortPage: DndContextProps['onDragEnd'] = (event) => {
    const { active, over } = event
    if (active.id !== over?.id) {
      const oldIndex = categoryAllPage.findIndex(
        (item) => item.id === active.id
      )
      const newIndex = categoryAllPage.findIndex((item) => item.id === over?.id)
      const afterSortPage = arrayMove(categoryAllPage, oldIndex, newIndex)
      const newGlobalData = globalData.map((g) => {
        if (g.groupId !== groupId) return g
        const { children } = g
        const newCategoryList = children.map((c) => {
          if (c.categoryId !== categoryId) return c
          return {
            ...c,
            pageData: afterSortPage,
          }
        })
        return {
          ...g,
          children: newCategoryList,
        }
      })
      dispatch(actions.setAllGlobalData(newGlobalData))
    }
  }

  const getPageUrl = (data: IContainer) => {
    return (
      data.children?.find((b) => b.component === 'Page')?.props?.imgUrl || ''
    )
  }

  return (
    <DndContext
      sensors={sensors}
      collisionDetection={closestCenter}
      onDragEnd={handleSortPage}
    >
      <SortableContext
        items={categoryAllPage}
        strategy={verticalListSortingStrategy}
      >
        {categoryAllPage?.map((data) => {
          const pageImage = getPageUrl(data)
          return (
            <SortableItem
              url={pageImage}
              data={data}
              key={data.id}
              switchPage={switchPage}
            />
          )
        })}
      </SortableContext>
    </DndContext>
  )
}

export default CategoryPages
