import { useTypedSelector } from '@/store'
import { useMemo } from 'react'

const useGetStatus = () => {
  const { status } = useTypedSelector((state) => state.paletteSlice)

  const isPublish = useMemo(() => {
    return status === 'published'
  }, [status])

  return {
    isPublish,
  }
}

export default useGetStatus
