import { Button } from 'antd'
import { PlusOutlined } from '@ant-design/icons'
import GroupListModal from '@/components/GroupListModal'
import { useTranslation } from 'react-i18next'
import { useState } from 'react'
import useGetStatus from '@/hooks/useGetStatus.ts'

const ButtonWithGroupModal = () => {
  const { t } = useTranslation()
  const [open, setOpen] = useState(false)
  const { isPublish } = useGetStatus()

  return (
    <>
      <Button
        disabled={isPublish}
        onClick={() => setOpen(true)}
        icon={<PlusOutlined />}
      >
        {t('operation.add_group')}
      </Button>
      {open && <GroupListModal open={open} setOpen={setOpen} />}
    </>
  )
}

export default ButtonWithGroupModal
