import type { IGroup } from '@/types/service'
import { getI18n } from 'react-i18next'

const menuGroupTree = (groups: IGroup[]) => {
  const t = getI18n().t
  return groups.map((group) => {
    return {
      value: group.id,
      title: t(`${group.id}`, {
        ns: 'group',
        defaultValue: group.name,
      }),
      children:
        group.menuCategories?.map((category) => {
          return {
            value: `${group.id}-${category.id}`,
            title: t(`${category.id}`, {
              ns: 'category',
              defaultValue: category.name,
            }),
          }
        }) || [],
    }
  })
}

export default menuGroupTree
