import styles from './DraggableBlockItem.module.less'
import type { allBlockTypes, BlockType } from '@/types/block'
import { useTranslation } from 'react-i18next'
import { useDraggable } from '@dnd-kit/core'
import { CSS } from '@dnd-kit/utilities'
import useGetStatus from '@/hooks/useGetStatus.ts'

interface IProps {
  block: BlockType<allBlockTypes>
}

const BlockItem = (props: IProps) => {
  const { t } = useTranslation()
  const { block } = props
  const { isPublish } = useGetStatus()

  const { setNodeRef, listeners, attributes, transform } = useDraggable({
    id: block.component,
    disabled: isPublish,
  })

  return (
    <div
      id={`blockItem-${block.component}`}
      style={{
        transform: CSS.Translate.toString(transform),
      }}
      className={styles.blockItem}
      ref={setNodeRef}
      {...listeners}
      {...attributes}
    >
      {t(block.label)}
    </div>
  )
}

export default BlockItem
