import { useEffect, useMemo, useState } from 'react'
import { Tree } from 'antd'
import styles from './ProductGrouping.module.less'
import { useTranslation } from 'react-i18next'
import { useAppDispatch, useTypedSelector } from '@/store'
import { actions } from '@/store/slices/productGrouping.slice.ts'
import { actions as paletteActions } from '@/store/slices/palette.slice.ts'
import type { TreeProps } from 'antd'
import ButtonWithGroupModal from './ButtonWithGroupModal.tsx'
import { ITemplateData } from '@/types/template'
import { MenuFoldOutlined, MenuUnfoldOutlined } from '@ant-design/icons'

type IKey = string | number | bigint
type IDropCategoryParams = {
  dragNodeCategoryId: number
  dropNodeGroupId: number
  insertPosition: number
}
type IDropGroupParams = {
  dragNodeGroupId: number
  insertPosition: number
}

const ProductGrouping = () => {
  const { t } = useTranslation()
  const dispatch = useAppDispatch()
  const { selectedMenu, selectedCategory } = useTypedSelector(
    (state) => state.productGroupingSlice
  )
  const { globalData } = useTypedSelector((state) => state.paletteSlice)
  const [expand, setExpand] = useState(true)

  const treeData = useMemo(() => {
    if (!selectedMenu?.length) return []
    return selectedMenu.map((group) => {
      return {
        key: group.id,
        title: t(`${group.id}`, {
          ns: 'group',
          defaultValue: group.name,
        }),
        selectable: false,
        children: group.menuCategories?.map((category) => {
          return {
            key: `${group.id}-${category.id}`,
            title: t(`${category.id}`, {
              ns: 'category',
              defaultValue: category.name,
            }),
          }
        }),
      }
    })
  }, [selectedMenu, t])

  useEffect(() => {
    if (selectedMenu) {
      dispatch(paletteActions.changeGlobalDataAfterSortMenu(selectedMenu))
    }
  }, [selectedMenu])

  useEffect(() => {
    if (!selectedCategory && treeData.length > 0) {
      dispatch(actions.setSelectedCategory([treeData[0].children[0].key]))
      return
    }
    // 删除模板后重置
    if (selectedCategory && !treeData.length) {
      dispatch(actions.setSelectedCategory(undefined))
    }
  }, [treeData, selectedCategory])

  const onSelect: TreeProps['onSelect'] = (selectedKeysValue) => {
    if (!selectedKeysValue.length) return
    dispatch(actions.setSelectedCategory(selectedKeysValue))
  }

  useEffect(() => {
    if (selectedCategory?.[0]) {
      const groupCategoryId = selectedCategory[0] as string
      const groupId = groupCategoryId.split('-')[0]
      const categoryId = groupCategoryId.split('-')[1]
      const defaultCategoryPage =
        globalData
          .find((g) => g.groupId === groupId)
          ?.children?.find((c) => c.categoryId === categoryId)?.pageData?.[0] ||
        ({} as ITemplateData['currentPageData'])
      dispatch(paletteActions.setCurrentPageData(defaultCategoryPage))
    }
  }, [selectedCategory])

  const getNodeKeyType = (key: IKey) =>
    typeof key === 'string' && key.includes('-') ? 'category' : 'group'
  const getNodeGroupId = (key: IKey) =>
    typeof key === 'number' ? key : Number((key as string).split('-')[0])

  // 通用的数组重排序函数
  const reorderArray = <T extends { id: number }>(
    array: T[],
    dragId: number,
    insertPosition: number
  ): T[] => {
    const newArray = [...array]
    const deleteItemIdx = newArray.findIndex((item) => item.id === dragId)

    if (deleteItemIdx > -1) {
      const [removed] = newArray.splice(deleteItemIdx, 1)
      let insertIdx = insertPosition
      if (insertIdx > deleteItemIdx) {
        insertIdx = insertIdx - 1
      }
      newArray.splice(insertIdx, 0, removed)
    }

    return newArray
  }

  // 类拖拽
  const afterDropCategory = (args: IDropCategoryParams) => {
    const { dragNodeCategoryId, dropNodeGroupId, insertPosition } = args
    const data = selectedMenu.map((group) => {
      if (group.id !== dropNodeGroupId) return group

      const newCategories = reorderArray(
        group.menuCategories,
        dragNodeCategoryId,
        insertPosition
      )

      return {
        ...group,
        menuCategories: newCategories.filter(Boolean),
      }
    })
    dispatch(actions.setSelectedMenu(data))
  }

  // 组拖拽
  const afterDropGroup = (args: IDropGroupParams) => {
    const { dragNodeGroupId, insertPosition } = args
    const newGroups = reorderArray(
      selectedMenu,
      dragNodeGroupId,
      insertPosition
    )
    dispatch(actions.setSelectedMenu(newGroups))
  }

  // 获取插入位置
  const getInsertPosition = (groupId: number, isGapTop = false): number => {
    const basePosition = selectedMenu.findIndex((group) => group.id === groupId)
    return isGapTop ? basePosition : basePosition + 1
  }

  // 简化的拖拽处理主函数
  const handleDropItem: TreeProps['onDrop'] = (args) => {
    const { node, dragNode } = args
    const dragNodeType = getNodeKeyType(dragNode.key)
    const dropNodeType = getNodeKeyType(node.key)
    const dragNodeGroupId = getNodeGroupId(dragNode.key)
    const dropNodeGroupId = getNodeGroupId(node.key)

    // 处理分类拖拽
    if (dragNodeType === 'category') {
      const dragNodeCategoryId = Number((dragNode.key as string).split('-')[1])

      // 类不能跨组
      if (dragNodeGroupId !== dropNodeGroupId) return

      let insertPosition: number

      if (dropNodeType === 'group') {
        insertPosition = 0
      } else {
        const dropNodeCategoryId = Number((node.key as string).split('-')[1])
        const categoryIndex = selectedMenu
          ?.find((group) => group.id === dragNodeGroupId)
          ?.menuCategories?.findIndex(
            (category) => category.id === dropNodeCategoryId
          )
        if (categoryIndex === undefined) return
        insertPosition = categoryIndex + 1
      }

      afterDropCategory({
        dragNodeCategoryId,
        dropNodeGroupId,
        insertPosition,
      })
      return
    }

    // 处理组拖拽
    if (dropNodeType === 'category') {
      // 组不能拖动到其他类中
      const nodeGroupChildren = treeData?.find(
        (each) => each.key === dropNodeGroupId
      )?.children
      const nodeIndex =
        nodeGroupChildren?.findIndex((each) => each.key === node.key) || -1
      const isLastOne =
        nodeIndex > -1 && nodeIndex === (nodeGroupChildren?.length || 0) - 1

      if (!isLastOne) return

      afterDropGroup({
        dragNodeGroupId,
        insertPosition: getInsertPosition(dropNodeGroupId),
      })
      return
    }

    // 拖拽到其他组
    afterDropGroup({
      dragNodeGroupId,
      insertPosition: getInsertPosition(dropNodeGroupId, node.dragOverGapTop),
    })
  }

  return (
    <>
      {expand ? (
        <div className={styles.grouping}>
          <main className={styles.main}>
            <div className={styles.title}>
              <span>{t('dish.grouping')}</span>
              <MenuFoldOutlined onClick={() => setExpand(false)} />
            </div>
            <div className={styles.dishTreeWrapper}>
              <div className={styles.dishTree}>
                {treeData?.length > 0 && (
                  <Tree
                    draggable
                    defaultExpandAll
                    selectedKeys={selectedCategory}
                    treeData={treeData}
                    onSelect={onSelect}
                    expandedKeys={treeData.map((g) => g.key)}
                    onDrop={handleDropItem}
                  />
                )}
              </div>
            </div>
          </main>
          <footer className={styles.footer}>
            <ButtonWithGroupModal />
          </footer>
        </div>
      ) : (
        <div className={styles.narrowMenu}>
          <MenuUnfoldOutlined onClick={() => setExpand(true)} />
        </div>
      )}
    </>
  )
}

export default ProductGrouping
