import { Resizable } from 're-resizable'
import type { ResizableProps } from 're-resizable'
import { ReactNode, useMemo } from 'react'
import type { IBusinessComp } from '@/types/template'
import { useTypedSelector } from '@/store'
import register from '@/utils/blockRegister.ts'

interface IProps {
  block: IBusinessComp
  children: ReactNode
  onResizeOver: (data: {
    blockId: string
    width: string
    height: string
  }) => void
}

const ResizeableBlock = (props: IProps) => {
  const { block, children, onResizeOver } = props
  const { currentBlock, viewportHeight, viewportWidth } = useTypedSelector(
    (state) => state.paletteSlice
  )

  const handleResizeStop: ResizableProps['onResizeStop'] = (
    _,
    __,
    elementRef
  ) => {
    onResizeOver({
      blockId: block.id,
      width: elementRef.style.width,
      height: elementRef.style.height,
    })
  }

  const isEnableResize = useMemo(() => {
    if (!currentBlock.id || !block.id) return false
    const blockOriginalInfo = register.getBlock(currentBlock.component)
    if (!blockOriginalInfo.resizable) return false
    return currentBlock.id === block.id
      ? {
          right: true,
          bottom: true,
          bottomRight: true,
        }
      : false
  }, [currentBlock, block])

  return (
    <Resizable
      size={{
        width: block.style.width,
        height: block.style.height,
      }}
      minWidth={block.style.minWidth}
      minHeight={block.style.minHeight}
      maxWidth={block.style.maxWidth || viewportWidth}
      maxHeight={block.style.maxHeight || viewportHeight}
      enable={isEnableResize}
      onResizeStop={handleResizeStop}
      style={{
        position: block.style.position,
        left: block.style.left,
        top: block.style.top,
        visibility: block.style.visibility || 'visible',
        zIndex: block.style.zIndex,
      }}
    >
      {children}
    </Resizable>
  )
}

export default ResizeableBlock
