import { useTypedSelector } from '@/store'
import { useMemo } from 'react'

const useGetCategoryData = () => {
  const { selectedCategory } = useTypedSelector(
    (state) => state.productGroupingSlice
  )
  const { globalData } = useTypedSelector((state) => state.paletteSlice)

  const groupId = useMemo(() => {
    if (selectedCategory?.[0]) {
      const groupCategoryId = selectedCategory[0] as string
      return groupCategoryId.split('-')[0]
    }
    return ''
  }, [selectedCategory])

  const categoryId = useMemo(() => {
    if (selectedCategory?.[0]) {
      const groupCategoryId = selectedCategory[0] as string
      return groupCategoryId.split('-')[1]
    }
    return ''
  }, [selectedCategory])

  const categoryAllPage = useMemo(() => {
    if (groupId && categoryId && globalData.length > 0) {
      return (
        globalData
          .find((group) => group.groupId === groupId)
          ?.children.find((category) => category.categoryId === categoryId)
          ?.pageData || []
      )
    }
    return []
  }, [groupId, categoryId, globalData])

  return {
    groupId,
    categoryId,
    categoryAllPage,
  }
}

export default useGetCategoryData
