import React from 'react'
import { Button, Modal, Form, Radio } from 'antd'
import { useTranslation } from 'react-i18next'
import UploadWithForm from '@/components/UploadWithForm'
import { useTypedSelector } from '@/store'

interface IProps {
  open: boolean
  setOpen: React.Dispatch<React.SetStateAction<boolean>>
  handleAddNewPage: (value: FieldType) => void
}

export type FieldType = {
  pageType: string
  imgUrls: string[]
}

const CreatePageModal = (props: IProps) => {
  const { t } = useTranslation()
  const { open, setOpen, handleAddNewPage } = props
  const [form] = Form.useForm()
  const activityType = Form.useWatch('pageType', form)
  const { width, height } = useTypedSelector((state) => state.paletteSlice)

  const handleCloseModal = () => {
    setOpen(false)
  }

  const handleConfirm = () => {
    form.validateFields().then((value: FieldType) => {
      handleAddNewPage(value)
      handleCloseModal()
    })
  }

  return (
    <Modal
      zIndex={900000}
      onCancel={handleCloseModal}
      open={open}
      title={t('operation.add_page')}
      footer={[
        <Button key="cancel" onClick={handleCloseModal}>
          {t('operation.cancel')}
        </Button>,
        <Button key="confirm" type="primary" onClick={handleConfirm}>
          {t('operation.confirm')}
        </Button>,
      ]}
    >
      <Form<FieldType>
        form={form}
        initialValues={{
          pageType: 'image',
          imgUrls: [],
        }}
      >
        <Form.Item label={t('palette.pageType')} name="pageType">
          <Radio.Group>
            <Radio value="image">{t('palette.image_page')}</Radio>
            <Radio value="empty">{t('palette.empty_page')}</Radio>
          </Radio.Group>
        </Form.Item>
        {activityType === 'image' && (
          <Form.Item
            label={t('palette.add_img')}
            name="imgUrls"
            rules={[
              {
                message: t('palette.add_img_error'),
                validator: (_, value) => {
                  if (!value || !value?.length)
                    return Promise.reject(
                      new Error(`${t('palette.add_img_error')}`)
                    )
                  return Promise.resolve()
                },
              },
            ]}
          >
            <UploadWithForm
              uploadConfig={{
                multiple: true,
                maxCount: 5,
              }}
              maxDimensions={{
                width,
                height,
              }}
              showImageDimensions={true}
            />
          </Form.Item>
        )}
      </Form>
    </Modal>
  )
}

export default CreatePageModal
