import styles from './index.module.less'
import type { ReactNode } from 'react'
import type { IBusinessComp } from '@/types/template'
import { useTypedSelector } from '@/store'
import DeleteBlock from './DeleteBlock'
import RecoverBlock from './RecoverBlock'

interface IProps {
  isNeedTooltipBar?: boolean
  children: ReactNode
  block: IBusinessComp
}

const TooltipBar = (props: IProps) => {
  const { isNeedTooltipBar = true, children, block } = props
  const { currentBlock } = useTypedSelector((state) => state.paletteSlice)

  return (
    <>
      {isNeedTooltipBar && currentBlock.id === block.id ? (
        <>
          <div className={styles.tooltipBar}>
            <RecoverBlock />
            <DeleteBlock />
          </div>
          {children}
        </>
      ) : (
        children
      )}
    </>
  )
}

export default TooltipBar
