import { useState } from 'react'
import { useTranslation } from 'react-i18next'
import { useAppDispatch, useTypedSelector } from '@/store'
import classNames from 'classnames'
import styles from './index.module.less'
import { PlusSquareOutlined } from '@ant-design/icons'
import CreatePageModal, {
  type FieldType,
} from '@/components/CreatePageModal/CreatePageModal.tsx'
import useGetStatus from '@/hooks/useGetStatus.ts'
import register from '@/utils/blockRegister.ts'
import type { IContainer } from '@/types/template'
import { nanoid } from 'nanoid'
import { actions, effects } from '@/store/slices/palette.slice.ts'
import useGetCategoryData from '@/hooks/useGetCategoryData.ts'
import { containerInitProps } from '@/constants/BlockProperties.ts'

const AddNewPage = () => {
  const [open, setOpen] = useState(false)
  const { isPublish } = useGetStatus()
  const { t } = useTranslation()
  const { globalData } = useTypedSelector((state) => state.paletteSlice)
  const dispatch = useAppDispatch()
  const { groupId, categoryId, categoryAllPage } = useGetCategoryData()

  const handleBeforeAddNewPage = () => {
    if (isPublish) return
    setOpen(true)
  }

  // 新增页
  const handleAddNewPage = (value: FieldType) => {
    const { imgUrls } = value
    const pageAttachBlock = register.getBlock('Page')
    const makeUpPage = (imgUrl: string) => {
      return {
        component: 'Container',
        id: nanoid(),
        sort: categoryAllPage?.length + 1,
        groupId,
        categoryId,
        children: [
          {
            id: nanoid(),
            component: pageAttachBlock.component,
            style: pageAttachBlock.style || {},
            props: {
              imgUrl,
            },
          },
        ],
        props: {
          ...containerInitProps,
        },
      } as IContainer
    }
    const newPage: IContainer[] = !imgUrls?.length
      ? [makeUpPage('')]
      : imgUrls.map((imgUrl) => makeUpPage(imgUrl))
    const newGroupData = globalData.map((g) => {
      if (g.groupId !== groupId) return g
      return {
        ...g,
        children: g.children.map((c) => {
          return {
            ...c,
            pageData:
              c.categoryId === categoryId
                ? [...categoryAllPage, ...newPage]
                : c.pageData,
          }
        }),
      }
    })
    dispatch(actions.setAllGlobalData(newGroupData))
    // 新增后 切换到新增页
    dispatch(actions.setCurrentPageData(newPage?.[0]))
    // 新增页后保存数据
    dispatch(effects.saveEMenuProConfig())
  }

  return (
    <>
      <div
        className={classNames(
          styles.addPage,
          isPublish && styles.addPageDisabled
        )}
        onClick={handleBeforeAddNewPage}
      >
        <PlusSquareOutlined />
        <span className={styles.addText}>{t('operation.add_page')}</span>
      </div>
      {open && (
        <CreatePageModal
          open={open}
          setOpen={setOpen}
          handleAddNewPage={handleAddNewPage}
        />
      )}
    </>
  )
}

export default AddNewPage
