import { useState } from 'react'
import BlockProperty from '@/components/BlockProperty'
import { useTranslation } from 'react-i18next'
import { useAppDispatch, useTypedSelector } from '@/store'
import styles from './BlockSetting.module.less'
import { Tabs, type TabsProps } from 'antd'
import { actions } from '@/store/slices/palette.slice.ts'
import BACK from '@/assets/images/back.png'
import type { IBusinessComp } from '@/types/template'

const BlockSetting = () => {
  const { t } = useTranslation()
  const { currentBlock } = useTypedSelector((state) => state.paletteSlice)
  const [tabActiveKey, setTabActiveKey] = useState('props')
  const dispatch = useAppDispatch()

  const items: TabsProps['items'] = [
    {
      key: 'props',
      label: t('blocks.props'),
    },
    // {
    //   key: 'events',
    //   label: t('blocks.event'),
    // },
  ]

  const onChange = (key: string) => {
    setTabActiveKey(key)
  }

  const handleShowBlockList = () => {
    dispatch(actions.setCurrentBlock({} as IBusinessComp))
  }

  return (
    <div className={styles.blockSetting} id="block_setting">
      <div className={styles.title}>
        <img
          src={BACK}
          alt="back to block list"
          onClick={handleShowBlockList}
          className={styles.rollback}
        />
        <span>{t('blocks.component_setting')}</span>
      </div>
      {!currentBlock.id ? (
        <div className={styles.tips}>{t('blocks.select_block_first')}</div>
      ) : (
        <>
          <Tabs activeKey={tabActiveKey} items={items} onChange={onChange} />
          {tabActiveKey === 'props' && <BlockProperty />}
        </>
      )}
    </div>
  )
}

export default BlockSetting
