import React, { useState } from 'react'
import { Button, message, Modal } from 'antd'
import DishTreeSelect from '@/components/MenuTreeSelect/DishTreeSelect.tsx'
import getCurrentCategoryDish from '@/utils/getCurrentCategoryDish.ts'
import { useTranslation } from 'react-i18next'
import { useAppDispatch, useTypedSelector } from '@/store'
import { actions } from '@/store/slices/palette.slice.ts'

interface IProps {
  open: boolean
  setOpen: React.Dispatch<React.SetStateAction<boolean>>
}

const BindDishModal = (props: IProps) => {
  const { t } = useTranslation()
  const { open, setOpen } = props
  const dispatch = useAppDispatch()
  const { currentBlock, currentPageData } = useTypedSelector(
    (state) => state.paletteSlice
  )
  const [tempDish, setTempDish] = useState<string | undefined>(undefined)

  const bindDishToCurrentBlock = () => {
    if (!tempDish) {
      message.warning(t('palette.select_bind_dish'))
      return
    }
    dispatch(actions.editCurrentBlockProps({ itemId: tempDish }))
    setOpen(false)
  }

  const handleCloseModal = () => {
    setOpen(false)
  }

  return (
    <Modal
      zIndex={900000}
      onCancel={handleCloseModal}
      title={t('blocks.bind_dish_property')}
      open={open}
      footer={[
        <Button key="cancel" onClick={handleCloseModal}>
          {t('operation.later')}
        </Button>,
        <Button key="confirm" type="primary" onClick={bindDishToCurrentBlock}>
          {t('operation.confirm')}
        </Button>,
      ]}
    >
      <DishTreeSelect
        value={currentBlock?.props?.itemId || tempDish}
        onChange={(val) => setTempDish(val)}
        resolveTreeData={(data) =>
          getCurrentCategoryDish({ currentPageData, data })
        }
      />
    </Modal>
  )
}

export default BindDishModal
