import ComponentProperty from './ComponentProperty.tsx'
import { useTypedSelector } from '@/store'
import { useMemo } from 'react'
import register from '@/utils/blockRegister.ts'

const BlockProperty = () => {
  const { currentBlock } = useTypedSelector((state) => state.paletteSlice)

  const isHasComponentProperty = useMemo(() => {
    if (!currentBlock.id) return false
    const blockInfo = register.getBlock(currentBlock.component)
    return blockInfo?.properties ? blockInfo.properties.length > 0 : false
  }, [currentBlock])

  if (!isHasComponentProperty) return null
  return <ComponentProperty />
}

export default BlockProperty
