import store from '@/store'
import { actions } from '@/store/slices/palette.slice.ts'
import type { IBusinessComp } from '@/types/template'

const removeCurrentBlock = () => {
  const { currentBlock, currentPageData, globalBlocks } =
    store.getState().paletteSlice
  if (currentBlock.component === 'Page') return
  store.dispatch(actions.removeCurrentBlock(currentBlock))
  if (currentBlock.props?.linkIds) {
    const currentPageAllBlocks = [
      ...(currentPageData?.children || []),
      ...(globalBlocks || []),
    ]
    currentPageAllBlocks.forEach((b) => {
      if (currentBlock.props?.linkIds?.includes(b.id)) {
        store.dispatch(actions.removeCurrentBlock(b))
      }
    })
  }
  store.dispatch(actions.setCurrentBlock({} as IBusinessComp))
}

export default removeCurrentBlock
