import React, { useState, useMemo, useEffect } from 'react'
import { useAppDispatch, useTypedSelector } from '@/store'
import { Button, Modal, message } from 'antd'
import { useTranslation } from 'react-i18next'
import MenuTreeSelect from '@/components/MenuTreeSelect'
import { actions } from '@/store/slices/productGrouping.slice.ts'
import { actions as paletteActions } from '@/store/slices/palette.slice.ts'
import type { IGroup } from '@/types/service'
import menuGroupTree from '@/utils/menuGroupTree.ts'
import styles from './index.module.less'

interface IProps {
  open: boolean
  setOpen: React.Dispatch<React.SetStateAction<boolean>>
}

const DishListModal = (props: IProps) => {
  const { t } = useTranslation()
  const { open, setOpen } = props
  const [value, setValue] = useState<string[]>([])
  const dispatch = useAppDispatch()
  const { selectedMenu } = useTypedSelector(
    (state) => state.productGroupingSlice
  )
  const { globalBlocks } = useTypedSelector((state) => state.paletteSlice)
  const { menus } = useTypedSelector((state) => state.menuSlice)

  const treeData = useMemo(() => {
    if (!menus?.length) return []
    return menuGroupTree(menus[0].menuGroups)
  }, [menus])

  useEffect(() => {
    if (!value.length && selectedMenu?.length && treeData.length) {
      const preSelectedMenuToTree = menuGroupTree(selectedMenu)
      const preValue = preSelectedMenuToTree.reduce((pre, cur) => {
        const subKeys = cur.children.map((item) => item.value)
        return pre.concat(subKeys)
      }, [] as string[])
      setValue(preValue)
    }
  }, [selectedMenu, value, treeData])

  const handleCloseModal = () => {
    setValue([])
    setOpen(false)
  }

  const handleSelectGroup = (val: string[] | string) => {
    if (Array.isArray(val)) {
      setValue(val)
    }
  }

  const handleConfirm = () => {
    if (!value.length) return message.warning(t('dish.noValue'))
    const groups = menus[0].menuGroups
    const allGroupId = [
      ...new Set(
        value.map((groupCateId) =>
          typeof groupCateId === 'string'
            ? Number(groupCateId.split('-')?.[0])
            : groupCateId
        )
      ),
    ] as number[]
    const allCategoryId = [
      ...new Set(
        value
          .map((groupCateId) =>
            typeof groupCateId === 'string'
              ? Number(groupCateId.split('-')?.[1])
              : undefined
          )
          .filter(Boolean)
      ),
    ]
    const selectedMenu = groups.reduce((pre, cur) => {
      if (allGroupId.includes(cur.id)) {
        const selectedCategory = (cur.menuCategories || []).filter((category) =>
          allCategoryId.includes(category.id)
        )
        const selectedGroup = {
          ...cur,
          menuCategories: selectedCategory,
        }
        return pre.concat(selectedGroup)
      }
      return pre
    }, [] as IGroup[])
    // 保存选择的菜单
    dispatch(actions.setSelectedMenu(selectedMenu))
    // 保存模板树数据
    handleInitGlobalBlocks()
    handleCloseModal()
  }

  useEffect(() => {
    if (selectedMenu) {
      dispatch(paletteActions.changeGlobalDataAfterSortMenu(selectedMenu))
    }
  }, [selectedMenu])

  const handleInitGlobalBlocks = () => {
    // 初始化全局组件
    if (!globalBlocks?.length) {
      dispatch(paletteActions.setInitGlobalBlocks())
    }
  }

  return (
    <Modal
      zIndex={900000}
      onCancel={handleCloseModal}
      title={t('dish.dish_dialog_modal_title')}
      open={open}
      footer={[
        <Button key="cancel" onClick={handleCloseModal}>
          {t('operation.cancel')}
        </Button>,
        <Button key="confirm" type="primary" onClick={handleConfirm}>
          {t('operation.confirm')}
        </Button>,
      ]}
    >
      <MenuTreeSelect
        treeData={treeData}
        value={value}
        onChange={handleSelectGroup}
        rootClassName={styles.customTree}
      />
    </Modal>
  )
}

export default DishListModal
