import { Button } from 'antd'
import { useTranslation } from 'react-i18next'
import { useCallback } from 'react'
import styles from './index.module.less'

interface Language {
  code: string
  labelKey: string
  toLabelKey: string
}

const SUPPORTED_LANGUAGES: Language[] = [
  {
    code: 'zh',
    labelKey: 'languageSwitcher.toChinese',
    toLabelKey: 'languageSwitcher.toEnglish',
  },
  {
    code: 'en',
    labelKey: 'languageSwitcher.toEnglish',
    toLabelKey: 'languageSwitcher.toChinese',
  },
]

const LanguageSwitcher = () => {
  const { t, i18n } = useTranslation()

  const currentLangIndex = Math.max(
    0,
    SUPPORTED_LANGUAGES.findIndex((lang) => lang.code === i18n.language)
  )

  const handleToggle = useCallback(() => {
    const nextIndex = (currentLangIndex + 1) % SUPPORTED_LANGUAGES.length
    i18n.changeLanguage(SUPPORTED_LANGUAGES[nextIndex].code)
  }, [currentLangIndex, i18n])

  const currentLanguage = SUPPORTED_LANGUAGES[currentLangIndex]

  return (
    <Button
      className={styles.languageSwitcher}
      onClick={handleToggle}
      type="text"
    >
      {currentLanguage
        ? t(currentLanguage.toLabelKey)
        : t(SUPPORTED_LANGUAGES[0].toLabelKey)}
    </Button>
  )
}

export default LanguageSwitcher
