import { UndoOutlined } from '@ant-design/icons'
import { useAppDispatch, useTypedSelector } from '@/store'
import register from '@/utils/blockRegister.ts'
import { actions } from '@/store/slices/palette.slice.ts'
import type { IBusinessComp } from '@/types/template'
import type { allBlocks } from '@/types/block'

const RecoverBlock = () => {
  const { currentBlock, currentPageData, globalBlocks } = useTypedSelector(
    (state) => state.paletteSlice
  )
  const dispatch = useAppDispatch()

  const isHasPosition = (originBlockInfo: allBlocks) => {
    return (
      'top' in (originBlockInfo.style || {}) &&
      'left' in (originBlockInfo.style || {}) &&
      ['absolute', 'fixed'].includes(originBlockInfo?.style?.position || '')
    )
  }

  const handleRecoverBlock = () => {
    const originBlockInfo = register.getBlock(currentBlock.component)
    const recoveredBlock = {
      ...currentBlock,
      props: {
        ...currentBlock.props,
        ...originBlockInfo.props,
      },
      style: isHasPosition(originBlockInfo)
        ? originBlockInfo.style
        : currentBlock.style,
      children: currentBlock.children?.map((b) => {
        const subOriginBlockInfo = register.getBlock(b.component)
        return {
          ...b,
          props: {
            ...b.props,
            ...subOriginBlockInfo.props,
          },
          style: isHasPosition(subOriginBlockInfo)
            ? subOriginBlockInfo.style
            : b.style,
        }
      }),
    }
    dispatch(actions.setCurrentBlock(recoveredBlock as IBusinessComp))
    if (currentBlock.props?.linkIds) {
      const currentPageAllBlocks = [
        ...(currentPageData?.children || []),
        ...(globalBlocks || []),
      ]
      currentPageAllBlocks.forEach((b) => {
        if (currentBlock.props?.linkIds?.includes(b.id)) {
          const linkBlockOriginInfo = register.getBlock(b.component)
          const recoverLinkInfo = {
            ...b,
            style: linkBlockOriginInfo.style || {},
            props: { ...b.props, ...linkBlockOriginInfo.props },
          }
          dispatch(
            register.getBlock(b.component)?.isGlobalBlock
              ? actions.syncGlobalBlocks(recoverLinkInfo)
              : actions.syncBlockDataToPage(recoverLinkInfo)
          )
        }
      })
    }
  }

  return <UndoOutlined onClick={handleRecoverBlock} />
}

export default RecoverBlock
