import { useState, useEffect } from 'react'
import styles from './Palette.module.less'
import { useAppDispatch, useTypedSelector } from '@/store'
import { useTranslation } from 'react-i18next'
import ButtonWithGroupModal from './ButtonWithGroupModal.tsx'
import { actions, effects } from '@/store/slices/palette.slice.ts'
import CurrentEditPage from './CurrentEditPage.tsx'
import type { IBusinessComp } from '@/types/template'
import register from '@/utils/blockRegister.ts'
import { InputNumber, Button } from 'antd'
import {
  checkBlockHeight,
  checkBlockWidth,
  checkPositionLeft,
  checkPositionTop,
  isPercentage,
} from '@/utils'
import NP from 'number-precision'
import { VIEWPORT_HEIGHT, VIEWPORT_WIDTH } from '@/constants/Viewport.ts'
import AddNewPage from '@/components/AddNewPage'

const Palette = () => {
  const { t } = useTranslation()
  const [modify, setModify] = useState(true)
  const [tempWidth, setTempWidth] = useState<null | number>(null)
  const [tempHeight, setTempHeight] = useState<null | number>(null)
  const dispatch = useAppDispatch()
  const {
    globalData,
    currentPageData,
    currentBlock,
    width,
    height,
    globalBlocks,
  } = useTypedSelector((state) => state.paletteSlice)
  const { selectedCategory } = useTypedSelector(
    (state) => state.productGroupingSlice
  )

  // 当前组件变化后保存到页面中
  useEffect(() => {
    if (currentBlock) {
      if (register.getBlock(currentBlock.component)?.isGlobalBlock) {
        dispatch(actions.syncGlobalBlocks(currentBlock))
        return
      }
      dispatch(actions.syncBlockDataToPage(currentBlock))
    }
  }, [currentBlock])
  // 当前页面数据变化后保存到全局中
  useEffect(() => {
    if (currentPageData.id) {
      dispatch(actions.syncPageDataToGroup())
    }
  }, [currentPageData])

  useEffect(() => {
    // 切页后 置空当前操作的组件
    dispatch(actions.setCurrentBlock({} as IBusinessComp))
  }, [currentPageData?.id])

  const resolveBlockNewStyle = (block: IBusinessComp) => {
    const { style } = block
    const { top, left, width, height } = style
    const newWidth = checkBlockWidth(width)
    const newHeight = checkBlockHeight(height)
    const newTop =
      typeof newHeight === 'string' && isPercentage(newHeight)
        ? top
        : checkPositionTop(newHeight, top as number)
    const newLeft =
      typeof newWidth === 'string' && isPercentage(newWidth)
        ? left
        : checkPositionLeft(newWidth, left as number)
    return {
      newWidth,
      newHeight,
      newTop,
      newLeft,
    }
  }

  const afterResizeViewport = async () => {
    const newGlobalData = globalData.map((group) => {
      return {
        ...group,
        children: group.children?.map((cate) => {
          return {
            ...cate,
            pageData: cate.pageData?.map((item) => {
              return {
                ...item,
                children: item.children?.map((block) => {
                  const { newWidth, newHeight, newTop, newLeft } =
                    resolveBlockNewStyle(block)
                  return {
                    ...block,
                    style: {
                      ...block.style,
                      width: newWidth,
                      height: newHeight,
                      top: newTop,
                      left: newLeft,
                    },
                  }
                }),
              }
            }),
          }
        }),
      }
    })
    dispatch(actions.setAllGlobalData(newGlobalData))
    const newGlobalBlocks = globalBlocks?.map((globalBlock) => {
      const { newWidth, newHeight, newTop, newLeft } =
        resolveBlockNewStyle(globalBlock)
      return {
        ...globalBlock,
        style: {
          ...globalBlock.style,
          width: newWidth,
          height: newHeight,
          top: newTop,
          left: newLeft,
        },
      }
    })
    dispatch(actions.setGlobalBlocks(newGlobalBlocks))
    await dispatch(effects.saveEMenuProConfig())
  }

  const handleConfirmModify = async () => {
    dispatch(actions.setSpinning(true))
    if (tempWidth) dispatch(actions.setTemplateWidth(tempWidth as number))
    if (tempHeight) dispatch(actions.setTemplateHeight(tempHeight as number))
    const actualWidth = tempWidth || width
    const actualHeight = tempHeight || height
    if (actualWidth && actualHeight) {
      const isHorizontal = actualWidth >= actualHeight
      dispatch(actions.setDirection(isHorizontal ? 'horizontal' : 'vertical'))
      const viewPortRate = isHorizontal
        ? NP.divide(actualHeight, actualWidth)
        : NP.divide(actualWidth, actualHeight)
      if (isHorizontal) {
        const viewportHeight = NP.times(VIEWPORT_WIDTH, viewPortRate)
        dispatch(
          actions.setViewPortSize({
            viewportWidth: VIEWPORT_WIDTH,
            viewportHeight: NP.round(viewportHeight, 2),
          })
        )
      } else {
        const viewportWidth = NP.times(VIEWPORT_HEIGHT, viewPortRate)
        dispatch(
          actions.setViewPortSize({
            viewportWidth: NP.round(viewportWidth, 2),
            viewportHeight: VIEWPORT_HEIGHT,
          })
        )
      }
      await afterResizeViewport()
      const t = setTimeout(() => {
        window.location.reload()
        clearTimeout(t)
      }, 1500)
    }
  }

  const handleCancelModify = () => {
    setModify(!modify)
    setTempWidth(null)
    setTempHeight(null)
  }

  return (
    <div className={styles.paletteWrapper}>
      {!selectedCategory?.length ? (
        <div className={styles.noData}>
          <span className={styles.text}>{t('palette.noData')}</span>
          <ButtonWithGroupModal />
        </div>
      ) : (
        <div className={styles.content}>
          {currentPageData?.id ? (
            <div className={styles.currentViewport}>
              <div className={styles.viewportSize}>
                <InputNumber
                  disabled={modify}
                  value={tempWidth || width}
                  style={{ width: 180, marginRight: 8 }}
                  addonBefore={t('style.width')}
                  addonAfter="px"
                  onChange={(val) => setTempWidth(val)}
                />
                <InputNumber
                  disabled={modify}
                  value={tempHeight || height}
                  style={{ width: 180 }}
                  addonBefore={t('style.height')}
                  addonAfter="px"
                  onChange={(val) => setTempHeight(val)}
                />
                {modify && (
                  <Button type="link" onClick={() => setModify(false)}>
                    {t('operation.modify')}
                  </Button>
                )}
                {!modify && (
                  <Button type="link" onClick={handleConfirmModify}>
                    {t('operation.confirm')}
                  </Button>
                )}
                {!modify && (
                  <Button type="link" onClick={handleCancelModify}>
                    {t('operation.cancel')}
                  </Button>
                )}
              </div>
              <CurrentEditPage />
            </div>
          ) : (
            <div className={styles.emptyPalette}>
              <AddNewPage />
            </div>
          )}
        </div>
      )}
    </div>
  )
}

export default Palette
