import { type ReactElement, useEffect, useMemo } from 'react'
import { useDraggable } from '@dnd-kit/core'
import type { IBusinessComp } from '@/types/template'
import { useTypedSelector } from '@/store'
import { CSS } from '@dnd-kit/utilities'
import styles from './index.module.less'
import register from '@/utils/blockRegister.ts'
import useGetStatus from '@/hooks/useGetStatus.ts'
import { useGlobalState } from '@/hooks/useGlobalState'

interface IProps {
  children: ReactElement
  block: IBusinessComp
}

const DraggableBlock = (props: IProps) => {
  const { children, block } = props
  const { isPublish } = useGetStatus()
  const isDraggable = useMemo(() => {
    if (!block.component) return false
    const blockOriginalInfo = register.getBlock(block.component)
    return blockOriginalInfo.draggable
  }, [block?.component])
  const [, setIsDragging] = useGlobalState('isDragging')

  const { setNodeRef, listeners, attributes, transform, isDragging } =
    useDraggable({
      id: block.id,
      disabled: !isDraggable || isPublish,
      data: block,
    })
  const { currentBlock } = useTypedSelector((state) => state.paletteSlice)

  useEffect(() => {
    setIsDragging(isDragging)
  }, [isDragging])

  return (
    <div
      className={
        currentBlock.id === block.id
          ? styles.currentResizeBlock
          : styles.resizeBlock
      }
      style={{
        position: 'static',
        left: 0,
        top: 0,
        width: '100%',
        height: '100%',
        cursor: isDraggable ? 'grab' : 'default',
        transform: CSS.Translate.toString(transform),
      }}
      ref={setNodeRef}
      {...listeners}
      {...attributes}
    >
      {children}
    </div>
  )
}

export default DraggableBlock
