import { DndContext, PointerSensor, useSensor, useSensors } from '@dnd-kit/core'
import { Button, Modal, Space, Spin } from 'antd'
import { useMount } from 'ahooks'
import { useTranslation } from 'react-i18next'
import styles from './index.module.less'
import ProductGrouping from './components/ProductGrouping.tsx'
import Palette from './components/Palette.tsx'
import BlockManagement from './components/BlockManagement.tsx'
import { useAppDispatch, useTypedSelector } from '@/store'
import { actions, effects } from '@/store/slices/palette.slice.ts'
import useGetStatus from '@/hooks/useGetStatus.ts'
import { IBusinessComp } from '@/types/template'
import {
  restrictToHorizontalAxis,
  restrictToVerticalAxis,
} from '@dnd-kit/modifiers'
import { useMemo } from 'react'
import register from '@/utils/blockRegister.ts'
import CategoryPages from '@/pages/Template/components/CategoryPages.tsx'
import useGetCategoryData from '@/hooks/useGetCategoryData.ts'
import AddNewPage from '@/components/AddNewPage'
import packageJson from './../../../package.json'
import LanguageSwitcher from '@/components/LanguageSwitcher'

const Template = () => {
  const { t } = useTranslation()
  const dispatch = useAppDispatch()
  const { isPublish } = useGetStatus()
  const { isHasTemplate, currentBlock, spinning } = useTypedSelector(
    (state) => state.paletteSlice
  )
  const [modal, contextHolder] = Modal.useModal()
  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 10,
      },
    })
  )
  const { selectedCategory } = useTypedSelector(
    (state) => state.productGroupingSlice
  )

  const modifiers = useMemo(() => {
    if (currentBlock.component) {
      const originInfo = register.getBlock(currentBlock.component)
      if (!originInfo.isRestrictDrag) return []
      return currentBlock.props?.direction === 'vertical'
        ? [restrictToVerticalAxis]
        : [restrictToHorizontalAxis]
    }
    return []
  }, [currentBlock.props?.direction])

  const { groupId, categoryId, categoryAllPage } = useGetCategoryData()

  useMount(() => {
    dispatch(effects.fetchEMenuProConfig())
  })

  const handleDeleteTemplate = () => {
    modal.confirm({
      title: t('palette.delete_template_confirm'),
      content: t('palette.delete_template_content'),
      classNames: {
        mask: styles.customModalMask,
        wrapper: styles.customModalWrapper,
      },
      onOk: () => dispatch(effects.deleteCurrentTemplate()),
    })
  }

  const handlePublishTemplate = () => {
    modal.confirm({
      title: t('palette.publish_template_confirm'),
      content: t('palette.publish_template_content'),
      classNames: {
        mask: styles.customModalMask,
        wrapper: styles.customModalWrapper,
      },
      onOk: () => {
        dispatch(actions.setCurrentBlock({} as IBusinessComp))
        dispatch(actions.changeTemplateStatus('published'))
        dispatch(effects.saveEMenuProConfig())
      },
    })
  }

  const handleEditTemplate = () => {
    modal.confirm({
      title: t('palette.edit_template_confirm'),
      content: t('palette.edit_template_content'),
      classNames: {
        mask: styles.customModalMask,
        wrapper: styles.customModalWrapper,
      },
      onOk: () => {
        dispatch(actions.changeTemplateStatus('draft'))
        dispatch(effects.saveEMenuProConfig())
      },
    })
  }

  return (
    <div className={styles.templateWrapper}>
      <div className={styles.header}>
        <div className={styles.leftSection}>
          <span className={styles.version}>v{packageJson.version}</span>
          <LanguageSwitcher />
        </div>
        <div className={styles.title}>{t('template.title')}</div>
        <Space size={8} className={styles.operationWrapper}>
          {isHasTemplate && (
            <Button
              onClick={handleDeleteTemplate}
              className={styles.deleteButton}
            >
              {t('operation.deleteTemplate')}
            </Button>
          )}
          {isHasTemplate && isPublish && (
            <Button onClick={handleEditTemplate}>{t('operation.edit')}</Button>
          )}
          {isHasTemplate && !isPublish && (
            <Button type="primary" onClick={handlePublishTemplate}>
              {t('operation.publish')}
            </Button>
          )}
        </Space>
      </div>
      <div className={styles.mainContent}>
        <ProductGrouping />
        {selectedCategory?.[0] ? (
          <div className={styles.menuDesign}>
            <CategoryPages
              groupId={groupId}
              categoryId={categoryId}
              categoryAllPage={categoryAllPage}
            />
            <AddNewPage />
          </div>
        ) : null}

        <DndContext sensors={sensors} modifiers={modifiers}>
          <Palette />
          <BlockManagement />
        </DndContext>
      </div>
      {contextHolder}
      <Spin spinning={spinning} fullscreen />
    </div>
  )
}

export default Template
