import type { DndContextProps } from '@dnd-kit/core'
import { type DragEndEvent, useDndMonitor } from '@dnd-kit/core'
import DroppableCanvas from '@/components/DroppablePalette/DroppableCanvas.tsx'
import ResizeableBlock from '@/components/ResizeableBlock'
import DraggableBlock from '@/components/DraggableBlock'
import { useAppDispatch, useTypedSelector } from '@/store'
import { actions } from '@/store/slices/palette.slice.ts'
import register from '@/utils/blockRegister.ts'
import type { allBlockTypes, BlockType } from '@/types/block'
import { CSSProperties, useEffect, useMemo, useState } from 'react'
import type { IBusinessComp } from '@/types/template'
import TooltipBar from '@/components/TooltipBar'
import { nanoid } from 'nanoid'
import useGetStatus from '@/hooks/useGetStatus.ts'
import BindDishModal from './BindDishModal.tsx'
import { checkPositionLeft, checkPositionTop } from '@/utils/index.ts'
import removeCurrentBlock from '@/utils/removeBlock.ts'

const DroppablePalette = () => {
  const [open, setOpen] = useState(false)
  const dispatch = useAppDispatch()
  const { isPublish } = useGetStatus()
  const allBlockKeys: allBlockTypes[] = [...register.getAllBlocks().keys()]

  const { currentPageData, globalBlocks } = useTypedSelector(
    (state) => state.paletteSlice
  )

  useEffect(() => {
    const removeBlock = (e: globalThis.KeyboardEvent) => {
      if (e.key === 'Delete') {
        removeCurrentBlock()
      }
    }
    document.addEventListener('keydown', removeBlock)
    return () => {
      document.removeEventListener('keydown', removeBlock)
    }
  }, [])

  const allEditableBlocks = useMemo(() => {
    return [...(currentPageData?.children || []), ...(globalBlocks || [])]
  }, [currentPageData, globalBlocks])

  const handleChangeBlockNewStyle = (
    blockId: string,
    changedStyle: CSSProperties
  ) => {
    const prevBlockInfo = allEditableBlocks?.find((b) => b.id === blockId)
    if (prevBlockInfo) {
      const newBlockInfo = {
        ...prevBlockInfo,
        style: {
          ...prevBlockInfo.style,
          ...changedStyle,
        },
      }
      dispatch(actions.setCurrentBlock(newBlockInfo))
    }
  }

  const handleBeforeDragBlock: DndContextProps['onDragPending'] = (e) => {
    const blockListWrapper = document.getElementById('block_list')
    if (blockListWrapper) {
      blockListWrapper.style.overflow = 'unset'
    }
    const { id } = e
    // 新增组件
    if (allBlockKeys.includes(id as allBlockTypes)) return
    // 拖动触发时设置当前block, 和点击为互斥事件
    const currentBlock =
      allEditableBlocks?.find((block) => block.id === id) ||
      ({} as IBusinessComp)
    dispatch(actions.setCurrentBlock(currentBlock))
  }

  const maxZIndex = useMemo(() => {
    const maxZIndexBlock = allEditableBlocks?.reduce((pre, cur) => {
      if (!pre.style?.zIndex) return cur
      if (Number(cur.style.zIndex) > Number(pre.style.zIndex)) return cur
      return pre
    }, {} as IBusinessComp)
    return Number(maxZIndexBlock?.style?.zIndex || 0) + 1
  }, [allEditableBlocks])

  const handleDragBlockStart: DndContextProps['onDragStart'] = (e) => {
    const { active } = e
    // 新增组件
    if (allBlockKeys.includes(active.id as allBlockTypes)) return
    // 拖动组件 更新zIndex
    handleChangeBlockNewStyle(String(active.id), { zIndex: maxZIndex })
    const componentType = active.data?.current?.component as allBlockTypes
    const blockOriginalInfo = register.getBlock(componentType)
    if (blockOriginalInfo.isGlobalBlock) return
    handleChangeGlobalBlockLayer()
  }

  // 全局组件层级永远在上
  const handleChangeGlobalBlockLayer = () => {
    const allZIndex = globalBlocks?.map(
      (each) => Number(each.style.zIndex) || 0
    )
    const minVal = Math.min(...(allZIndex || []))
    const offset = maxZIndex - minVal
    const newGlobalBlocks = globalBlocks?.map((each) => {
      return {
        ...each,
        style: {
          ...each.style,
          zIndex: Number(each.style.zIndex || 0) + offset,
        },
      }
    })
    dispatch(actions.setGlobalBlocks(newGlobalBlocks))
  }

  const makeUpBlock = (
    block: BlockType<allBlockTypes>,
    event: DragEndEvent
  ) => {
    const blockWidth = block.style?.width
    const blockHeight = block.style?.height
    const getTop = () => {
      return block.isGlobalBlock
        ? (block.style?.top ?? 0)
        : (event.activatorEvent as MouseEvent).clientY -
            (event?.over?.rect?.top || 0) +
            event.delta.y -
            Number(blockHeight) / 2
    }
    const getLeft = () => {
      return block.isGlobalBlock
        ? (block.style?.left ?? 0)
        : (event.activatorEvent as MouseEvent).clientX -
            (event?.over?.rect?.left || 0) +
            event.delta.x -
            Number(blockWidth) / 2
    }
    const blocksInfo = []
    const blockInfo = {
      id: nanoid(),
      component: block.component,
      style: {
        ...block.style,
        position: 'absolute',
        top: checkPositionTop(block.style?.height, getTop()),
        left: checkPositionLeft(block.style?.width, getLeft()),
        zIndex: maxZIndex,
      },
      props: block.props,
      children: block.children?.map((child) => {
        const childBlockInfo = register.getBlock(child)
        return {
          id: nanoid(),
          component: child,
          style: childBlockInfo.style,
          props: childBlockInfo.props,
        }
      }),
    } as IBusinessComp
    blocksInfo.push(blockInfo)
    if (block?.linkComponents?.length) {
      block?.linkComponents.forEach((blockType) => {
        const blockOriginalInfo = register.getBlock(blockType)
        blocksInfo.push(makeUpBlock(blockOriginalInfo, event)[0])
      })
    }
    if (blocksInfo.length > 1) {
      const blockIds = blocksInfo.map((b) => b.id)
      return blocksInfo.map((b) => {
        return {
          ...b,
          props: {
            ...b.props,
            linkIds: blockIds.filter((id) => id !== b.id),
          },
        }
      })
    }
    return blocksInfo
  }

  const handelAddNewBlockToPage = (
    blockOriginalInfo: BlockType<allBlockTypes>,
    event: DragEndEvent
  ) => {
    const newChildData = makeUpBlock(blockOriginalInfo, event)
    const newCurrentPageData = {
      ...currentPageData,
      children: [...(currentPageData?.children || []), ...newChildData],
    }
    dispatch(actions.setCurrentPageData(newCurrentPageData))
    dispatch(actions.setCurrentBlock(newChildData[0]))
    if (blockOriginalInfo?.properties?.includes('bindDish')) {
      // 选择绑定菜弹窗
      setOpen(true)
    }
  }

  const handleAddNewGlobalBlock = (
    blockOriginalInfo: BlockType<allBlockTypes>,
    event: DragEndEvent
  ) => {
    const isExist = globalBlocks?.find(
      (b) => b.component === blockOriginalInfo.component
    )
    if (isExist) return
    const newGlobalBlocks = [
      ...(globalBlocks || []),
      ...makeUpBlock(blockOriginalInfo, event),
    ]
    dispatch(actions.setGlobalBlocks(newGlobalBlocks))
  }

  const handleDragBlockEnd: DndContextProps['onDragEnd'] = (event) => {
    const blockListWrapper = document.getElementById('block_list')
    if (blockListWrapper) {
      blockListWrapper.style.overflow = 'auto'
    }
    const { active, over, delta } = event
    if (!over) return
    // 新增组件
    if (allBlockKeys.includes(active.id as allBlockTypes)) {
      // 新增全局组件
      const blockOriginalInfo = register.getBlock(active.id as allBlockTypes)
      if (blockOriginalInfo.isGlobalBlock) {
        handleAddNewGlobalBlock(blockOriginalInfo, event)
        return
      }
      // 新增页面组件
      handelAddNewBlockToPage(blockOriginalInfo, event)
      handleChangeGlobalBlockLayer()
      return
    }
    const oldBlock = allEditableBlocks?.find((block) => block.id === active.id)
    const oldBlockStyle = oldBlock?.style
    // 更新block位置
    if (oldBlockStyle) {
      const newBlockPosition = {
        top: checkPositionTop(
          oldBlock.style.height,
          Number(oldBlockStyle.top) + delta.y
        ),
        left: checkPositionLeft(
          oldBlock.style.width,
          Number(oldBlockStyle.left) + delta.x
        ),
      }
      handleChangeBlockNewStyle(String(active.id), newBlockPosition)
    }
  }

  const handleDragAbort: DndContextProps['onDragAbort'] = () => {
    const blockListWrapper = document.getElementById('block_list')
    if (blockListWrapper) {
      blockListWrapper.style.overflow = 'auto'
    }
  }

  const handleDragCancel: DndContextProps['onDragCancel'] = () => {
    const blockListWrapper = document.getElementById('block_list')
    if (blockListWrapper) {
      blockListWrapper.style.overflow = 'auto'
    }
  }

  useDndMonitor({
    onDragPending: handleBeforeDragBlock,
    onDragStart: handleDragBlockStart,
    onDragEnd: handleDragBlockEnd,
    onDragAbort: handleDragAbort,
    onDragCancel: handleDragCancel,
  })

  const handleResizeOver = (data: {
    blockId: string
    width: string
    height: string
  }) => {
    const { blockId, width, height } = data
    // 更新block大小
    handleChangeBlockNewStyle(blockId, { width, height })
  }

  // 点击组件
  const handleSelectBlock = (block: IBusinessComp) => {
    if (isPublish) return
    // 点击时设置当前block, 和拖动为互斥事件
    dispatch(actions.setCurrentBlock(block))
  }

  return (
    <>
      <DroppableCanvas id={currentPageData?.id}>
        {allEditableBlocks?.map((block) => {
          const blockInfo = register.getBlock(block.component)
          if (!blockInfo) return null
          return (
            <ResizeableBlock
              key={block.id}
              block={block}
              onResizeOver={handleResizeOver}
            >
              <DraggableBlock block={block}>
                <TooltipBar
                  block={block}
                  isNeedTooltipBar={blockInfo.isNeedTooltipBar}
                >
                  <div
                    style={{ width: '100%', height: '100%' }}
                    onClick={() => handleSelectBlock(block)}
                  >
                    {blockInfo.render(block)}
                  </div>
                </TooltipBar>
              </DraggableBlock>
            </ResizeableBlock>
          )
        })}
      </DroppableCanvas>
      {open && <BindDishModal open={open} setOpen={setOpen} />}
    </>
  )
}

export default DroppablePalette
