import { Button, message, Modal } from 'antd'
import { useAppDispatch, useTypedSelector } from '@/store'
import type { IBusinessComp, IContainer } from '@/types/template'
import { actions, effects } from '@/store/slices/palette.slice.ts'
import { useTranslation } from 'react-i18next'
import styles from './CurrentEditPage.module.less'
import DroppablePalette from '@/components/DroppablePalette'
import useGetStatus from '@/hooks/useGetStatus.ts'

const CurrentEditPage = () => {
  const { t } = useTranslation()
  const dispatch = useAppDispatch()
  const { globalData, currentPageData } = useTypedSelector(
    (state) => state.paletteSlice
  )
  const [modal, contextHolder] = Modal.useModal()
  const { isPublish } = useGetStatus()

  // 删除并切换页
  const handleDeletePage = () => {
    modal.confirm({
      title: t('palette.delete_page_confirm'),
      classNames: {
        mask: styles.customModalMask,
        wrapper: styles.customModalWrapper,
      },
      onOk: handleConfirmDeletePage,
    })
  }
  const handleConfirmDeletePage = () => {
    const { groupId, categoryId, id } = currentPageData
    let sameCategoryPageData = [] as IContainer[]
    const newGroupData = globalData.map((g) => {
      if (g.groupId !== groupId) return g
      return {
        ...g,
        children: g.children.map((c) => {
          if (c.categoryId === categoryId) {
            sameCategoryPageData = c.pageData.filter((p) => p.id !== id)
          }
          return {
            ...c,
            pageData:
              c.categoryId === categoryId ? sameCategoryPageData : c.pageData,
          }
        }),
      }
    })
    // 清空相关数据
    dispatch(actions.setAllGlobalData(newGroupData))
    dispatch(actions.setCurrentBlock({} as IBusinessComp))
    dispatch(
      actions.setCurrentPageData(
        sameCategoryPageData?.length > 0
          ? sameCategoryPageData[0]
          : ({} as IContainer)
      )
    )
    // 删除页后保存数据
    dispatch(effects.saveEMenuProConfig())
  }

  const handleSaveCurrentPage = () => {
    dispatch(actions.syncPageDataToGroup())
    message.success(t('operation.save_success'))
    dispatch(effects.saveEMenuProConfig())
  }

  return (
    <div className={styles.templateContent}>
      <div className={styles.viewportWrapper}>
        {/*<div className={styles.ratio}>*/}
        {/*  {t('palette.aspect_ratio')}: {aspectRatio}*/}
        {/*</div>*/}
        <DroppablePalette />
      </div>
      <footer className={styles.operationFooter}>
        <Button
          disabled={isPublish}
          className={styles.operationDel}
          onClick={handleDeletePage}
        >
          {t('operation.deleteMenu')}
        </Button>
        <Button
          disabled={isPublish}
          type="primary"
          onClick={handleSaveCurrentPage}
        >
          {t('operation.save')}
        </Button>
      </footer>
      {contextHolder}
    </div>
  )
}

export default CurrentEditPage
